import React, { FC } from 'react';
import { Box, Image } from 'grommet';

import csaba192 from '../../assets/csaba192.jpg';
import csaba384 from '../../assets/csaba384.jpg';

interface Props {
  size?: string;
}

const Avatar: FC<Props> = ({ size }) => (
  <Box flex={false} width={size} height={size} round="full" overflow="hidden">
    <Image
      srcSet={`${csaba192} 1x, ${csaba384} 2x`}
      src={csaba192}
      alt="Csaba Palfi"
    />
  </Box>
);

Avatar.defaultProps = {
  size: 'small',
};

// TODO remove docs component when https://github.com/storybookjs/storybook/issues/9794 is fixed
export const DocsAvatar: FC<Props> = props => <Avatar {...props} />;
DocsAvatar.defaultProps = Avatar.defaultProps;

export default Avatar;
